export const remainingC = [
  { id: 'aws', title: 'AWS', description: 'Amazon Web Services — the largest cloud platform.',
    officialDocs: 'https://docs.aws.amazon.com/', tutorialLink: 'https://aws.amazon.com/getting-started/', exerciseLink: null,
    sections: [
      { title: 'What is AWS', content: `Amazon Web Services is the world's largest cloud computing platform, offering 200+ services from data centers globally. AWS provides Infrastructure as a Service (IaaS), Platform as a Service (PaaS), and Software as a Service (SaaS).\n\nCore services: EC2 (virtual servers), S3 (object storage), RDS (managed databases), Lambda (serverless functions), VPC (networking), IAM (security), CloudFront (CDN), Route 53 (DNS). Most modern applications use a combination of these services.`, keyPoints: ['Largest cloud provider with 200+ services.', 'EC2, S3, RDS, Lambda are the core services.', 'IAM manages security and access control.', 'Pay only for what you use (pay-as-you-go).'] },
      { title: 'Core Services Overview', content: `EC2 (Elastic Compute Cloud): Virtual servers in the cloud. Choose instance types based on CPU/memory needs. Auto Scaling groups automatically add/remove instances based on demand.\n\nS3 (Simple Storage Service): Object storage for any file type. Globally durable (99.999999999% — 11 nines). Use for static websites, backups, data lakes, and CDN origins.\n\nLambda: Run code without managing servers. Pay only for compute time consumed. Triggered by events (API Gateway, S3 uploads, SQS messages). Auto-scales to millions of requests.\n\nRDS: Managed relational databases (PostgreSQL, MySQL, SQL Server). Handles backups, patching, scaling, and replication automatically.`, code: `# AWS CLI — common commands\naws configure                           # Set credentials\naws s3 sync ./dist s3://my-bucket       # Deploy static site\naws ec2 describe-instances              # List servers\naws lambda invoke --function-name myFunc out.json\n\n# Terraform (Infrastructure as Code)\nresource "aws_s3_bucket" "website" {\n  bucket = "my-website-bucket"\n}\nresource "aws_lambda_function" "api" {\n  filename      = "lambda.zip"\n  function_name = "my-api"\n  handler       = "index.handler"\n  runtime       = "nodejs20.x"\n}`, codeLabel: 'AWS CLI & Terraform', keyPoints: ['EC2 for servers, S3 for storage, Lambda for serverless.', 'Use Infrastructure as Code (Terraform/CloudFormation).', 'Auto Scaling adjusts resources to match demand.', 'RDS handles database maintenance automatically.'] },
      { title: 'Deployment Patterns', content: `Static websites: S3 + CloudFront (CDN). APIs: API Gateway + Lambda (serverless) or EC2 + Load Balancer. Containers: ECS (Elastic Container Service) or EKS (Elastic Kubernetes Service).\n\nCI/CD: CodePipeline orchestrates build-test-deploy. CodeBuild compiles and tests. CodeDeploy pushes to EC2/ECS. Or use GitHub Actions with AWS deployment actions.\n\nAlways use IAM roles (not access keys) for service-to-service communication. Use VPC to isolate your network. Enable CloudTrail for audit logging.`, keyPoints: ['S3 + CloudFront for static sites and CDNs.', 'Lambda + API Gateway for serverless APIs.', 'ECS/EKS for containerized applications.', 'Always use IAM roles, never hardcode credentials.'] }
    ]
  },
  { id: 'gcp', title: 'GCP', description: 'Google Cloud Platform — built on Google infrastructure.',
    officialDocs: 'https://cloud.google.com/docs', tutorialLink: 'https://cloud.google.com/docs/get-started', exerciseLink: null,
    sections: [
      { title: 'What is GCP', content: `Google Cloud Platform runs on the same infrastructure that Google uses for Search, YouTube, and Gmail. It excels in data analytics (BigQuery), Kubernetes (GKE), machine learning (Vertex AI), and serverless (Cloud Run).\n\nGCP organizes resources into Projects. Each project has its own billing, IAM, and API settings. The gcloud CLI and Cloud Console (web UI) are the primary interaction methods.`, keyPoints: ['Runs on Google\'s global infrastructure.', 'Industry-leading Kubernetes (GKE) and BigQuery.', 'Resources organized into Projects.', 'Cloud Run: serverless containers in seconds.'] },
      { title: 'Key Services', content: `Compute Engine: Virtual machines (like AWS EC2). Cloud Run: Deploy containers without managing infrastructure — auto-scales to zero. GKE: Managed Kubernetes, the industry standard. App Engine: Fully managed PaaS for web apps.\n\nCloud Storage: Object storage (like S3). Cloud SQL: Managed PostgreSQL/MySQL. Firestore: Serverless document database. BigQuery: Serverless data warehouse processing petabytes in seconds.`, code: `# gcloud CLI\ngcloud init                              # Setup\ngcloud projects list                      # List projects\n\n# Deploy container to Cloud Run\ngcloud run deploy my-service \\\n  --source . \\\n  --region us-central1 \\\n  --allow-unauthenticated\n\n# Deploy to App Engine\ngcloud app deploy\n\n# Create GKE cluster\ngcloud container clusters create my-cluster \\\n  --num-nodes=3 --zone=us-central1-a`, codeLabel: 'GCP Commands', keyPoints: ['Cloud Run deploys containers serverlessly.', 'GKE is the gold standard for Kubernetes.', 'BigQuery processes petabytes in seconds.', 'gcloud CLI for all infrastructure management.'] }
    ]
  },
  { id: 'azure-devops', title: 'Azure DevOps', description: 'Microsoft CI/CD and project management suite.',
    officialDocs: 'https://learn.microsoft.com/en-us/azure/devops/', tutorialLink: 'https://learn.microsoft.com/en-us/azure/devops/get-started/', exerciseLink: null,
    sections: [
      { title: 'What is Azure DevOps', image: '/images/azure-devops/suite-overview.svg', content: `Azure DevOps is Microsoft's end-to-end platform for planning work, storing source code, automating builds, releasing software, and managing internal package feeds. It gives teams one place to move from idea to production instead of stitching together separate tools for planning, coding, validation, and deployment.\n\nThe platform has five core services: Azure Boards for work tracking, Azure Repos for Git source control, Azure Pipelines for CI/CD, Azure Test Plans for manual and exploratory testing, and Azure Artifacts for package feeds. Teams commonly begin with Repos and Pipelines, then add Boards, approvals, environments, tests, and package feeds as their delivery workflow matures.\n\nAzure DevOps is especially common in .NET and Azure-based organizations, but the concepts it teaches are broader than Microsoft tooling: pull requests, branch policies, automated testing, artifact promotion, deployment approvals, and infrastructure as code are core DevOps practices in any stack.`, keyPoints: ['The five core services are Boards, Repos, Pipelines, Test Plans, and Artifacts.', 'Azure DevOps combines planning, source control, validation, and release workflows.', 'Repos and Pipelines usually provide the fastest early value.', 'The underlying DevOps practices transfer beyond Microsoft tooling.'] },
      { title: 'Portal, Projects & Boards', content: `The Azure DevOps portal is the central UI where teams create projects, manage repositories, run pipelines, assign work, and monitor release history. A project usually maps to one application, one platform area, or one delivery team.\n\nBoards helps teams organize work into epics, features, user stories, bugs, and tasks. Those items can be planned into sprints or visualized on Kanban boards. Dashboards then surface progress, blockers, build health, and deployment status so both engineers and stakeholders can see how work is moving.\n\nA useful beginner mental model is this: Boards answers what should be built, Repos answers where the code lives, and Pipelines answers how the change is validated and released.`, keyPoints: ['Projects are the top-level container for code, work items, pipelines, and dashboards.', 'Boards supports epics, stories, bugs, tasks, sprints, and Kanban views.', 'Dashboards make delivery status visible.', 'Linking work items to code and pipelines improves traceability.'] },
      { title: 'Repos, Pull Requests & Branching Strategy', image: '/images/azure-devops/branching-strategy.svg', content: `Azure Repos provides Git repositories plus the policy controls that keep shared branches stable. The usual workflow is feature branching: developers create short-lived branches, push commits there, open pull requests into development or main, and let automated checks plus reviewer approval decide whether the branch is safe to merge.\n\nA practical branching model for many teams is main for production-ready code, development for integrated ongoing work, feature branches for isolated implementation, release branches for stabilization, and hotfix branches for urgent production fixes. The exact names matter less than the safety rules around them.\n\nBranch policies are where Azure DevOps becomes much more than simple Git hosting. You can require reviewers, block direct pushes, demand linked work items, enforce build validation, require comment resolution, and limit who can complete a pull request.`, code: `# Typical Azure Repos workflow\ngit checkout development\ngit pull origin development\n\ngit checkout -b feature/user-profile\n\ngit add .\ngit commit -m "feat: add profile edit form"\n\ngit push -u origin feature/user-profile\n\n# Open a Pull Request into development or main\n# Protected branches should normally reject direct pushes`, codeLabel: 'Branching Workflow', keyPoints: ['Use feature branches and merge through pull requests.', 'Protect main and development with reviewer and build-validation policies.', 'Release branches stabilize a version; hotfix branches repair production quickly.', 'Branch strategy exists to reduce risk, not to create extra ceremony.'] },
      { title: 'YAML Pipelines Fundamentals', image: '/images/azure-devops/ci-cd-flow.svg', content: `Azure Pipelines defines CI/CD in YAML so delivery logic lives in source control beside the application code. That means the pipeline can be reviewed, versioned, and improved through pull requests exactly like the application itself.\n\nA pipeline is triggered by an event such as a push, pull request, schedule, or manual run. Inside the pipeline, stages group major phases like Build, Test, and Deploy. Each stage contains jobs, and each job contains steps. Steps are the concrete scripts or reusable tasks that actually run.\n\nThis stage-job-step hierarchy is the key concept beginners should learn first. Once that model is clear, most Azure Pipelines YAML becomes much easier to read.`, code: `trigger:\n  branches:\n    include:\n      - main\n\npool:\n  vmImage: 'ubuntu-latest'\n\nstages:\n- stage: Build\n  jobs:\n  - job: BuildWeb\n    steps:\n    - task: UseDotNet@2\n      inputs:\n        version: '8.x'\n    - script: dotnet restore\n    - script: dotnet build --configuration Release\n\n- stage: Test\n  dependsOn: Build\n  jobs:\n  - job: RunTests\n    steps:\n    - script: dotnet test --no-build --configuration Release`, codeLabel: 'Basic YAML Structure', keyPoints: ['Stages group delivery phases, jobs define execution units, and steps run commands.', 'Pipeline code should live in YAML so it can be reviewed and versioned.', 'Common triggers are push, pull request, schedule, and manual runs.', 'Understanding structure matters more than memorizing task names.'] },
      { title: 'CI/CD, Artifacts & Environments', content: `Continuous Integration means every code change is built and validated early, usually on every push or pull request. The goal is fast feedback: if a change breaks compilation, tests, packaging, or static checks, the team learns immediately.\n\nContinuous Delivery and Continuous Deployment extend that flow by taking a validated artifact and releasing it to one or more environments such as dev, test, staging, or production. The artifact matters because it separates build time from deploy time. You build once, then promote the same output forward instead of rebuilding different versions for each stage.\n\nAzure DevOps environments make releases safer by attaching approvals, checks, and history to each target. That gives teams a controlled path from validated code to live systems.`, code: `stages:\n- stage: Build\n  jobs:\n  - job: PublishArtifact\n    steps:\n    - script: dotnet publish -c Release -o out\n    - task: PublishBuildArtifacts@1\n      inputs:\n        PathtoPublish: 'out'\n        ArtifactName: 'webapp'\n\n- stage: Deploy\n  dependsOn: Build\n  jobs:\n  - deployment: DeployToProd\n    environment: 'production'\n    strategy:\n      runOnce:\n        deploy:\n          steps:\n          - download: current\n            artifact: webapp`, codeLabel: 'Artifacts & Environments', keyPoints: ['CI validates changes quickly through builds and tests.', 'CD promotes already-built artifacts through environments.', 'Build once, deploy many times is safer than rebuilding per environment.', 'Environments provide approval gates and deployment history.'] },
      { title: 'Microsoft-hosted vs Self-hosted Agents', image: '/images/azure-devops/self-hosted-agent.svg', content: `Agents are the machines that actually execute pipeline jobs. Microsoft-hosted agents are disposable VMs managed by Microsoft, and they are the easiest starting point because every run begins on a clean environment.\n\nSelf-hosted agents run on your own machine, VM, or on-premises server. They are useful when the build depends on custom installed software, private network access, internal package feeds, or deployment targets that hosted agents cannot reach. Setting one up usually requires a Personal Access Token, an agent pool, the downloaded agent package, and config.cmd or config.sh.\n\nThe tradeoff is responsibility. Self-hosted agents give more control, but the team must patch them, secure them, monitor capacity, and keep their tools up to date.`, code: `# Windows self-hosted agent setup (simplified)\nC:/agents\n./config.cmd\n\n# During setup provide:\n# - Server URL: https://dev.azure.com/your-organization\n# - Authentication: PAT\n# - Agent pool name: MyLocalPool\n# - Agent name: MyLocalMachineAgent\n\npool:\n  name: MyLocalPool`, codeLabel: 'Self-hosted Agent Basics', keyPoints: ['Agents are the machines that run pipeline jobs.', 'Hosted agents are simpler; self-hosted agents are more flexible.', 'Use self-hosted agents for private network access or custom toolchains.', 'Owning the agent also means owning its security and maintenance.'] },
      { title: 'Variables, Secrets & Variable Groups', image: '/images/azure-devops/variable-precedence.svg', content: `Azure Pipelines supports variables in several places: YAML, pipeline settings, queue time, and shared variable groups. Understanding precedence is important because the same name can resolve differently depending on where it is defined.\n\nVariable groups are the reusable layer. They are ideal for environment-specific values, shared configuration, and secrets that several pipelines need. They can also integrate with Azure Key Vault so sensitive values stay out of the repository and out of plain YAML.\n\nWhen the same variable appears in multiple scopes, higher-precedence scopes win. Queue-time values override pipeline values, job-level YAML overrides stage-level YAML, stage-level overrides root-level values, and variable groups are lower precedence than direct pipeline definitions.`, code: `variables:\n- group: ProdSecrets\n\n- name: environmentName\n  value: 'production'\n\nstages:\n- stage: Deploy\n  variables:\n    connectionName: 'prod-service-connection'\n  jobs:\n  - job: DeployApp\n    variables:\n      slotName: 'blue'\n    steps:\n    - script: echo Deploying $(environmentName) to $(slotName)`, codeLabel: 'Variables & Variable Groups', keyPoints: ['Variable groups provide shared configuration across multiple pipelines.', 'Store secrets in protected groups or Key Vault, not in source control.', 'Queue-time and job-level values can override broader defaults.', 'Precedence rules matter whenever the same variable exists in multiple scopes.'] },
      { title: 'Deploying ARM Templates with YAML', image: '/images/azure-devops/iac-pipeline.svg', content: `Infrastructure as Code is one of the strongest Azure DevOps use cases. Instead of creating Azure resources through manual portal clicks, teams define the target infrastructure in code and deploy it through a reviewed, repeatable pipeline. For Azure-native deployments, ARM templates are one standard option.\n\nThe usual pattern is: keep the ARM template and parameter files in the repository, create an Azure Resource Manager service connection, validate the template in CI, and then deploy with AzureResourceManagerTemplateDeployment@3. Because the deployment runs in CI/CD, infrastructure changes are reviewed, logged, and reproducible.\n\nThis reinforces a core DevOps rule: production environments should be created from code, not from undocumented manual steps.`, code: `trigger:\n- main\n\npool:\n  vmImage: 'ubuntu-latest'\n\nsteps:\n- task: AzureResourceManagerTemplateDeployment@3\n  displayName: 'Deploy ARM Template'\n  inputs:\n    deploymentScope: 'Resource Group'\n    azureResourceManagerConnection: 'MyAzureSC'\n    subscriptionId: '$(subscriptionId)'\n    action: 'Create Or Update Resource Group'\n    resourceGroupName: 'MyResourceGroup'\n    location: 'westeurope'\n    templateLocation: 'Linked artifact'\n    csmFile: '$(Build.SourcesDirectory)/templates/azuredeploy.json'\n    csmParametersFile: '$(Build.SourcesDirectory)/templates/azuredeploy.parameters.json'\n    deploymentMode: 'Incremental'`, codeLabel: 'ARM Deployment Pipeline', keyPoints: ['Keep ARM templates and parameter files in Git.', 'Use a service connection instead of manual portal authentication.', 'AzureResourceManagerTemplateDeployment@3 is the standard ARM deployment task.', 'Infrastructure should be reviewed and repeatable like application code.'] },
      { title: 'Terraform with Azure DevOps', content: `Terraform is another common Infrastructure as Code option in Azure DevOps, especially when a team wants one tool that can manage Azure plus other platforms. Instead of describing only Azure resources, Terraform uses providers to manage many systems with the same workflow.\n\nA typical beginner sequence is straightforward: write the provider and resource blocks, run terraform init to install providers, terraform plan to preview changes, and terraform apply only after review. In production teams, apply should usually happen through a pipeline so changes are centralized, audited, and protected by branch policies.\n\nThe attached notes emphasize the right habits: keep Terraform in Git, use variables instead of hardcoding values, review the plan before apply, and keep secrets out of code. Those habits matter more than memorizing every Terraform argument.`, code: `trigger:\n- main\n\npool:\n  vmImage: 'windows-latest'\n\nsteps:\n- task: TerraformInstaller@0\n  inputs:\n    terraformVersion: '1.14.0'\n\n- task: TerraformTask@5\n  inputs:\n    command: 'init'\n\n- task: TerraformTask@5\n  inputs:\n    command: 'plan'\n    commandOptions: '-out=tfplan'\n\n- task: TerraformTask@5\n  inputs:\n    command: 'apply'\n    commandOptions: 'tfplan'\n  condition: and(succeeded(), eq(variables['Build.SourceBranch'], 'refs/heads/main'))`, codeLabel: 'Terraform Pipeline', keyPoints: ['Terraform uses provider-based infrastructure as code.', 'The core workflow is init, plan, and apply.', 'Review plan output before apply, especially on shared environments.', 'Pipeline-owned apply is safer than ad hoc local execution in production.'] },
      { title: 'Best Practices for Learning Azure DevOps', content: `The fastest way to learn Azure DevOps is to build a small real workflow end to end: create a project, push a sample app to Azure Repos, protect the main branch, write a YAML pipeline, publish an artifact, add an environment, and deploy either a tiny app or an ARM template.\n\nFocus on concepts in this order: repository workflow, pull requests, branch policies, build validation, artifact publishing, environment approvals, variable management, and infrastructure as code. Once those are clear, the portal becomes easier to navigate because every menu has a purpose.\n\nA strong beginner rule set is simple: keep pipeline logic in YAML, keep secrets out of code, prefer small pull requests, make validation builds mandatory on protected branches, and let automation handle repetitive deployment work.`, keyPoints: ['Learn Azure DevOps by building a small end-to-end workflow, not by reading menus only.', 'Master Git, PRs, policies, CI, artifacts, environments, and IaC in that order.', 'Keep secrets out of repos and pipeline YAML whenever possible.', 'Small pull requests and mandatory validation builds are the safest default.'] }
    ]
  },
  { id: 'data-structure', title: 'Data Structures', description: 'Organizing data for efficient access and modification.',
    officialDocs: null, tutorialLink: 'https://www.w3schools.com/dsa/', exerciseLink: 'https://leetcode.com/',
    sections: [
      { title: 'What are Data Structures', content: `Data structures define how data is organized, stored, and accessed in memory. Choosing the right data structure dramatically affects application performance — the difference between O(1) and O(n) lookups can mean milliseconds vs minutes.\n\nLinear structures store data sequentially: Arrays, Linked Lists, Stacks, Queues. Non-linear structures store data hierarchically or relationally: Trees, Graphs, Hash Maps, Heaps.`, keyPoints: ['Right structure = fast app, wrong structure = slow app.', 'Linear: Arrays, Linked Lists, Stacks, Queues.', 'Non-linear: Trees, Graphs, Hash Maps, Heaps.', 'Big-O notation measures time/space complexity.'] },
      { title: 'Arrays & Linked Lists', content: `Arrays store elements contiguously in memory. Access by index is O(1), but insertion/deletion in the middle is O(n) because elements must shift. Use when you need fast random access.\n\nLinked Lists store elements as nodes with pointers. Insertion/deletion is O(1) if you have a reference to the node, but access by index is O(n) because you must traverse. Use when you need frequent insertions/deletions.`, code: `// Array — O(1) access, O(n) insertion\nconst arr = [10, 20, 30, 40];\narr[2];          // O(1) — instant access\narr.splice(1, 0, 15); // O(n) — shift elements\n\n// Linked List — O(1) insert, O(n) access\nclass Node {\n  constructor(val) { this.val = val; this.next = null; }\n}\nclass LinkedList {\n  constructor() { this.head = null; }\n  prepend(val) {  // O(1)\n    const node = new Node(val);\n    node.next = this.head;\n    this.head = node;\n  }\n  find(val) {  // O(n)\n    let curr = this.head;\n    while (curr) {\n      if (curr.val === val) return curr;\n      curr = curr.next;\n    }\n    return null;\n  }\n}`, codeLabel: 'Array vs Linked List', keyPoints: ['Array: O(1) read, O(n) insert/delete.', 'Linked List: O(1) insert/delete, O(n) read.', 'Arrays for random access, lists for frequent mutations.'] },
      { title: 'Stacks, Queues & Hash Maps', content: `Stack (LIFO — Last In, First Out): Think of a stack of plates. push() adds to top, pop() removes from top. Used for undo functionality, function call stacks, bracket matching.\n\nQueue (FIFO — First In, First Out): Think of a line at a store. enqueue() adds to back, dequeue() removes from front. Used for task scheduling, BFS traversal, message queues.\n\nHash Map (O(1) average lookup): Maps keys to values using a hash function. JavaScript's Map and Object, Python's dict, Java's HashMap. Used for caching, counting frequencies, fast lookups.`, code: `// Stack (LIFO)\nconst stack = [];\nstack.push("A"); stack.push("B"); stack.push("C");\nstack.pop();  // "C" (last in, first out)\n\n// Queue (FIFO)\nconst queue = [];\nqueue.push("A"); queue.push("B"); queue.push("C");\nqueue.shift(); // "A" (first in, first out)\n\n// Hash Map — O(1) lookups\nconst wordCount = new Map();\nconst words = ["hello", "world", "hello", "js"];\nfor (const w of words) {\n  wordCount.set(w, (wordCount.get(w) || 0) + 1);\n}\n// Map { "hello" => 2, "world" => 1, "js" => 1 }`, codeLabel: 'Stacks, Queues & Hash Maps', keyPoints: ['Stack: LIFO — undo, call stacks, backtracking.', 'Queue: FIFO — scheduling, BFS, message processing.', 'Hash Map: O(1) key-value lookups.', 'Choose based on access pattern: LIFO, FIFO, or key-based.'] },
      { title: 'Trees & Big-O Notation', content: `Trees are hierarchical structures with a root node and child nodes. Binary Search Trees (BST) maintain order: left children are smaller, right children are larger. This enables O(log n) search, insert, and delete.\n\nBig-O Notation measures how performance scales with input size: O(1) constant, O(log n) logarithmic, O(n) linear, O(n log n) linearithmic, O(n²) quadratic. Always aim for the lowest complexity possible.`, code: `// Binary Search Tree\nclass TreeNode {\n  constructor(val) {\n    this.val = val;\n    this.left = null;\n    this.right = null;\n  }\n}\nclass BST {\n  constructor() { this.root = null; }\n  insert(val, node = this.root) {\n    if (!this.root) { this.root = new TreeNode(val); return; }\n    if (val < node.val) {\n      if (!node.left) node.left = new TreeNode(val);\n      else this.insert(val, node.left);\n    } else {\n      if (!node.right) node.right = new TreeNode(val);\n      else this.insert(val, node.right);\n    }\n  }\n}\n\n// Big-O Cheat Sheet\n// O(1)      — Hash Map lookup\n// O(log n)  — Binary Search, BST operations\n// O(n)      — Linear search, single loop\n// O(n log n) — Merge Sort, Quick Sort\n// O(n²)     — Nested loops (Bubble Sort)`, codeLabel: 'BST & Big-O', keyPoints: ['BST: O(log n) search, insert, delete.', 'O(1) < O(log n) < O(n) < O(n log n) < O(n²).', 'Use balanced trees (AVL, Red-Black) to guarantee O(log n).', 'Always analyze complexity before choosing an algorithm.'] }
    ]
  },
  { id: 'sys-arch', title: 'System Architecture', description: 'Designing scalable, reliable software systems.',
    officialDocs: null, tutorialLink: 'https://github.com/donnemartin/system-design-primer', exerciseLink: null,
    sections: [
      { title: 'Architecture Patterns', content: `Monolithic: All code in one deployable unit. Simple to develop and deploy initially, but harder to scale and maintain as it grows. Microservices: System split into small, independent services communicating via APIs. Each service is deployed, scaled, and maintained independently.\n\nEvent-Driven: Services communicate through events/messages (Kafka, RabbitMQ) rather than direct API calls. Enables loose coupling and async processing. Serverless: Cloud provider manages infrastructure entirely. You deploy functions (AWS Lambda) that auto-scale and charge per execution.`, keyPoints: ['Monolith: simple start, hard to scale.', 'Microservices: independent, scalable, complex.', 'Event-driven: loose coupling via message queues.', 'Serverless: zero infrastructure management.'] },
      { title: 'Scalability & Load Balancing', content: `Vertical scaling adds more power to one server (more CPU/RAM). Horizontal scaling adds more servers. Horizontal scaling is preferred because it has no upper limit and provides redundancy.\n\nLoad balancers distribute incoming traffic across multiple servers. Algorithms: Round Robin, Least Connections, IP Hash. Health checks automatically remove unhealthy servers from rotation.\n\nCaching (Redis, Memcached) stores frequently accessed data in memory, reducing database load. CDNs (Content Delivery Networks) cache static assets globally for faster delivery.`, keyPoints: ['Horizontal scaling > vertical scaling.', 'Load balancers distribute traffic across servers.', 'Caching reduces database load dramatically.', 'CDNs deliver static assets globally.'] },
      { title: 'CAP Theorem & Database Scaling', content: `The CAP Theorem states a distributed system can guarantee only 2 of 3: Consistency (every read returns the latest write), Availability (every request gets a response), and Partition Tolerance (system works despite network failures).\n\nDatabase scaling: Read replicas handle read traffic separately from writes. Sharding splits data across multiple database instances by a key (user ID, region). Connection pooling reuses database connections to prevent exhaustion.`, keyPoints: ['CAP: choose 2 of Consistency, Availability, Partition Tolerance.', 'Read replicas for scaling read-heavy workloads.', 'Sharding distributes data across multiple databases.', 'Design for failure — assume any component can crash.'] }
    ]
  },
  { id: 'design-patterns', title: 'Design Patterns', description: 'Proven solutions to common software design problems.',
    officialDocs: null, tutorialLink: 'https://refactoring.guru/design-patterns', exerciseLink: null,
    sections: [
      { title: 'What are Design Patterns', content: `Design patterns are reusable solutions to commonly occurring problems in software design. Cataloged by the "Gang of Four" (GoF), they provide a shared vocabulary for developers.\n\nThree categories: Creational (how objects are created), Structural (how objects are composed), Behavioral (how objects interact). Patterns are not code — they are templates that guide your design decisions.`, keyPoints: ['Proven solutions, not code to copy-paste.', 'Three categories: Creational, Structural, Behavioral.', 'Gang of Four (GoF) cataloged 23 classic patterns.', 'Don\'t force patterns — use them when the problem fits.'] },
      { title: 'Creational Patterns', content: `Singleton: Ensures only one instance of a class exists (database connection pool, logger). Factory Method: Creates objects without specifying exact classes, using a factory interface. Builder: Constructs complex objects step-by-step (useful when constructors have many parameters).`, code: `// Singleton (Module pattern in JS)\nclass Database {\n  static #instance = null;\n  static getInstance() {\n    if (!Database.#instance) {\n      Database.#instance = new Database();\n    }\n    return Database.#instance;\n  }\n}\n\n// Factory\nclass NotificationFactory {\n  static create(type) {\n    switch(type) {\n      case 'email': return new EmailNotification();\n      case 'sms': return new SMSNotification();\n      case 'push': return new PushNotification();\n    }\n  }\n}\nconst notif = NotificationFactory.create('email');\n\n// Builder\nconst query = new QueryBuilder()\n  .select("name", "email")\n  .from("users")\n  .where("active = true")\n  .orderBy("name")\n  .build();`, codeLabel: 'Creational Patterns', keyPoints: ['Singleton: one global instance (use sparingly).', 'Factory: create objects without specifying exact class.', 'Builder: step-by-step complex object construction.'] },
      { title: 'Structural & Behavioral Patterns', content: `Structural — Adapter: Converts one interface into another that clients expect. Decorator: Adds behavior to objects dynamically without modifying their code. Facade: Provides a simplified interface to a complex subsystem.\n\nBehavioral — Observer: Objects subscribe to events and get notified when state changes (React state, event emitters). Strategy: Defines a family of interchangeable algorithms (sorting strategies, payment methods). Command: Encapsulates a request as an object (undo/redo functionality).`, code: `// Observer Pattern\nclass EventEmitter {\n  #listeners = {};\n  on(event, fn) {\n    (this.#listeners[event] ??= []).push(fn);\n  }\n  emit(event, data) {\n    this.#listeners[event]?.forEach(fn => fn(data));\n  }\n}\n\nconst bus = new EventEmitter();\nbus.on('userCreated', (user) => sendWelcomeEmail(user));\nbus.on('userCreated', (user) => logActivity(user));\nbus.emit('userCreated', { name: 'Alice' });\n\n// Strategy Pattern\nconst strategies = {\n  credit: (amount) => chargeCard(amount),\n  paypal: (amount) => paypalCheckout(amount),\n  crypto: (amount) => cryptoTransfer(amount),\n};\nfunction checkout(method, amount) {\n  return strategies[method](amount);\n}`, codeLabel: 'Structural & Behavioral', keyPoints: ['Observer: event-driven communication (pub/sub).', 'Strategy: interchangeable algorithms at runtime.', 'Adapter: make incompatible interfaces work together.', 'Decorator: add behavior without modifying original code.'] }
    ]
  },
  { id: 'github', title: 'GitHub', description: 'World\'s largest platform for version control and collaboration.',
    officialDocs: 'https://docs.github.com/', tutorialLink: 'https://docs.github.com/en/get-started/quickstart', exerciseLink: null,
    sections: [
      { title: 'What is GitHub', content: `GitHub is a cloud-based platform for hosting Git repositories, enabling collaboration, code review, and project management. It hosts over 200 million repositories and is the center of open-source development.\n\nGit is a distributed version control system created by Linus Torvalds in 2005. It tracks every change made to your code, allowing you to revert to any previous state, compare changes over time, and collaborate with others without overwriting each other's work.\n\nGitHub adds a web-based layer on top of Git, providing a visual interface, Pull Requests for code review, Issues for tracking bugs and features, Projects for Kanban boards, Actions for CI/CD automation, Pages for free static site hosting, and Packages for artifact registries.\n\nEvery professional developer must know Git and GitHub. It is used by virtually every software company worldwide — from startups to enterprises like Google, Microsoft, Facebook, and Amazon.`, image: 'https://images.unsplash.com/photo-1618401471353-b98afee0b2eb?w=800&auto=format&fit=crop&q=60', keyPoints: ['200M+ repositories — the largest developer platform.', 'Git tracks every change — revert, compare, branch freely.', 'Pull Requests enable structured code review.', 'Issues + Projects for project management.', 'GitHub Actions for CI/CD automation.', 'GitHub Pages for free static website hosting.'] },
      { title: 'Git Installation & Setup', content: `Before using GitHub, you need to install Git on your local machine. Git is available for Windows, macOS, and Linux.\n\nStep 1: Visit https://git-scm.com/downloads and download the latest version for your operating system.\n\nStep 2: Run the installer. On Windows, accept the default settings (ensure "Git Bash" is included). On macOS, you can also install via Homebrew: brew install git. On Linux: sudo apt install git (Ubuntu/Debian) or sudo yum install git (CentOS/RHEL).\n\nStep 3: Verify the installation by opening a terminal and running git --version. You should see the installed version number.\n\nStep 4: Configure your identity. Git needs your name and email to tag every commit you make. This is essential for collaboration — your team sees who made each change.`, code: `# Download & Install Git\n# Visit: https://git-scm.com/downloads\n# Download for your OS and install\n\n# Verify installation\ngit --version\n# Output: git version 2.44.0\n\n# Configure your identity (REQUIRED)\ngit config --global user.name "Your Full Name"\ngit config --global user.email "your.email@company.com"\n\n# Verify configuration\ngit config --global --list\n# Output:\n# user.name=Your Full Name\n# user.email=your.email@company.com\n\n# Optional: Set default branch name to 'main'\ngit config --global init.defaultBranch main\n\n# Optional: Set VS Code as default editor\ngit config --global core.editor "code --wait"`, codeLabel: 'Git Installation & Configuration', keyPoints: ['Download Git from git-scm.com/downloads.', 'git config sets your name and email for commits.', 'Use --global flag to apply settings to all repositories.', 'Always verify with git --version after installation.'] },
      { title: 'Create GitHub Account', content: `To use GitHub, you need a free account. GitHub offers free unlimited public and private repositories.\n\nStep 1: Visit https://github.com and click "Sign Up."\n\nStep 2: Enter your email address (preferably your company/work email for professional repositories). Choose a username that is professional and recognizable — this becomes your public identity (e.g., github.com/yourusername).\n\nStep 3: Create a strong password and verify your email address. GitHub will send a verification code.\n\nStep 4: After verification, you will be taken to the dashboard. Note your username, email, and password — you will need them for Git configuration and authentication.\n\nStep 5: Set up Two-Factor Authentication (2FA) under Settings → Password and Authentication. This is highly recommended (and required for many organizations) for account security.\n\nGitHub Plans: Free (unlimited repos, 2000 Actions minutes/month), Team ($4/user/month — advanced collaboration), and Enterprise ($21/user/month — SSO, audit logs, compliance).`, keyPoints: ['Visit github.com and sign up with your email.', 'Choose a professional, recognizable username.', 'Enable Two-Factor Authentication (2FA) for security.', 'Free plan includes unlimited public and private repos.', 'Note your username, email, and password.'] },
      { title: 'Create a Repository', content: `A repository (repo) is a folder that Git tracks. It contains your project files, the entire change history, and branch information.\n\nCreate a New Repository on GitHub:\n1. Log in to github.com\n2. Click the "+" icon at the top right → "New repository"\n3. Enter a repository name (e.g., "developer-guide")\n4. Add an optional description\n5. Choose visibility: Public (anyone can see) or Private (only you and invited collaborators)\n6. Optionally initialize with a README, .gitignore, and license\n7. Click "Create repository"\n\nAfter creating the repository on GitHub, you'll see quick setup instructions showing how to connect a local project to this remote repository.`, code: `# === Option 1: Create a new repository from scratch ===\necho "# developer-guide" >> README.md\ngit init\ngit add README.md\ngit commit -m "first commit"\ngit branch -M main\ngit remote add origin https://github.com/antonyrobin/developer-guide.git\ngit push -u origin main\n\n# === Option 2: Push an existing local project ===\ngit remote add origin https://github.com/antonyrobin/developer-guide.git\ngit branch -M main\ngit push -u origin main\n\n# === Option 3: Clone an existing repository ===\ngit clone https://github.com/antonyrobin/developer-guide.git\ncd developer-guide`, codeLabel: 'Repository Creation Commands', keyPoints: ['git init initializes a new local Git repository.', 'git remote add origin connects local repo to GitHub.', 'git clone downloads an existing repo from GitHub.', 'Choose Public or Private visibility based on your needs.', '-M flag renames the default branch to main.'] },
      { title: 'Setup Repository Locally', content: `To work on a GitHub repository from your computer, you need to clone it or connect your local folder to the remote repository.\n\nCloning downloads the entire repository including all branches and history. Connecting an existing folder adds the remote URL so you can push/pull changes.\n\nAfter connecting, use git pull to download the latest code from the remote branch before starting your work. This ensures you have the most up-to-date code and prevents merge conflicts.`, code: `# Navigate to your projects directory\ncd /path/to/your/projects\n\n# Clone a repository (downloads everything)\ngit clone https://github.com/antonyrobin/developer-guide.git\ncd developer-guide\n\n# --- OR connect an existing folder ---\ncd my-existing-project\ngit init\ngit remote add origin https://github.com/antonyrobin/developer-guide.git\n\n# Switch to the development branch\ngit checkout -b development\n\n# Pull the latest code from remote\ngit pull origin development\n\n# Verify remote connection\ngit remote -v\n# Output:\n# origin  https://github.com/antonyrobin/developer-guide.git (fetch)\n# origin  https://github.com/antonyrobin/developer-guide.git (push)\n\n# See all branches (local + remote)\ngit branch -a`, codeLabel: 'Local Repository Setup', keyPoints: ['git clone downloads the full repo with history.', 'git remote add origin connects to a remote URL.', 'Always git pull before starting new work.', 'git remote -v verifies your remote connection.'] },
      { title: 'Add, Commit & Push Files', image: '/images/github-workflow.png', content: `The Git workflow follows three stages: Working Directory (your changes) → Staging Area (selected changes) → Repository (committed snapshot).\n\ngit add selects which changes to include in the next commit. git add . stages ALL changed files. git add filename stages a specific file.\n\ngit commit creates a permanent snapshot of the staged changes with a descriptive message. Commit messages should be clear and explain WHY the change was made, not just WHAT changed.\n\ngit push uploads your local commits to the remote GitHub repository. The first push to a new branch requires the -u flag (upstream tracking). After that, just git push is enough.\n\nCommit Message Best Practices: Use the conventional format: type: description. Types: feat (new feature), fix (bug fix), docs (documentation), style (formatting), refactor (code restructuring), test (tests), chore (maintenance).`, code: `# === Using Command Line ===\n\n# Stage all changed files\ngit add .\n\n# Stage specific file(s)\ngit add src/App.jsx src/index.css\n\n# Check what is staged\ngit status\n\n# Commit with a descriptive message\ngit commit -m "feat: add user authentication module"\n\n# Push to remote branch (first time)\ngit push -u origin username/dev\n\n# Push to remote branch (subsequent pushes)\ngit push\n\n# === Using IDE (VS Code) ===\n# 1. Select the correct branch (bottom-left corner)\n# 2. Pull latest changes (sync button)\n# 3. Make your code changes\n# 4. Open Source Control panel (Ctrl+Shift+G)\n# 5. Stage changes (+ icon next to files)\n# 6. Write commit message in the text box\n# 7. Click Commit, then Push\n\n# === Quick Commit Shortcut ===\n# Stage + Commit in one command\ngit commit -am "fix: resolve login redirect bug"`, codeLabel: 'Add, Commit & Push', keyPoints: ['git add . stages all changes for commit.', 'git commit -m creates a snapshot with a message.', 'git push uploads commits to GitHub.', 'Use conventional commit messages: feat:, fix:, docs:.', 'In VS Code: Source Control panel → Stage → Commit → Push.'] },
      { title: 'Push, Pull & Fetch', content: `These three commands manage data transfer between your local repository and the remote GitHub repository.\n\ngit push: Uploads your local commits to the remote repository. Only the current branch is pushed. If the remote has newer commits, push will be rejected — you must pull first.\n\ngit pull: Downloads AND merges remote changes into your current branch. It is equivalent to git fetch + git merge. Always pull before starting new work to avoid conflicts.\n\ngit fetch: Downloads remote changes but does NOT merge them. It updates your knowledge of the remote branches without changing your working code. Use this when you want to review changes before merging.\n\nCommon issue: "rejected — non-fast-forward." This means someone else pushed changes to the same branch. Solution: git pull first, resolve any conflicts, then git push again.`, code: `# Push local commits to remote\ngit push origin development\n\n# Pull latest changes from remote (fetch + merge)\ngit pull origin development\n\n# Fetch without merging (safe preview)\ngit fetch origin\ngit log origin/development  # See what changed\ngit merge origin/development # Then merge manually\n\n# Pull with rebase (cleaner history)\ngit pull --rebase origin development\n\n# Force push (DANGEROUS — only for your own branches)\ngit push --force origin username/dev\n\n# Push a new local branch to remote for the first time\ngit push -u origin feature/new-dashboard\n\n# See tracking relationship\ngit branch -vv`, codeLabel: 'Push, Pull & Fetch Commands', keyPoints: ['git push uploads local commits to remote.', 'git pull downloads AND merges remote changes.', 'git fetch downloads changes WITHOUT merging.', 'Always pull before push to avoid conflicts.', 'Never force push to shared branches (main, development).'] },
      { title: 'Branch Creation & Management', image: '/images/github-branching.png', content: `Branches let you work on features, fixes, or experiments without affecting the main codebase. Each branch is an independent line of development.\n\nCommon branching strategy:\n- main — Production-ready code. Only merged via Pull Requests.\n- development — Integration branch where features are combined.\n- feature/xyz — Individual feature branches created from development.\n- hotfix/xyz — Emergency fixes branched from main.\n\nNaming conventions: Use prefixes to categorize branches. Examples: feature/user-auth, bugfix/login-error, hotfix/security-patch, username/task-name.\n\nAlways create feature branches from the latest development branch. Never commit directly to main or development — always use Pull Requests.`, code: `# Create a new branch and switch to it\ngit checkout -b feature/user-auth\n\n# Same as above (modern syntax)\ngit switch -c feature/user-auth\n\n# Switch to an existing branch\ngit checkout development\ngit switch development\n\n# List all local branches\ngit branch\n\n# List all branches (local + remote)\ngit branch -a\n\n# Delete a local branch (after merge)\ngit branch -d feature/user-auth\n\n# Delete a remote branch\ngit push origin --delete feature/user-auth\n\n# Rename current branch\ngit branch -M new-branch-name\n\n# Create branch from development\ngit checkout development\ngit pull origin development\ngit checkout -b username/task-name`, codeLabel: 'Branch Commands', keyPoints: ['git checkout -b creates and switches to a new branch.', 'Always branch from the latest development code.', 'Use prefixes: feature/, bugfix/, hotfix/, username/.', 'Delete branches after they are merged.', 'Never commit directly to main or development.'] },
      { title: 'Pull Request Creation & Review', image: '/images/github-pr-flow.png', content: `A Pull Request (PR) is a request to merge your branch's changes into another branch (usually development or main). PRs enable code review, discussion, and quality control before changes are integrated.\n\nCreating a Pull Request:\n1. Push your branch to GitHub: git push -u origin username/dev\n2. Visit https://github.com and navigate to your repository\n3. Click the "Pull Requests" tab\n4. Click "New Pull Request"\n5. Select Base branch (development) and Compare branch (your branch)\n6. Write a clear title and description explaining your changes\n7. Click "Create Pull Request"\n\nPR Review Process:\n- Reviewers examine the code diff, leave comments, and suggest changes\n- "Approve" — Code is good to merge\n- "Request Changes" — Author must address feedback before merging\n- "Comment" — General feedback without approval or rejection\n\nAfter all reviewers approve and CI checks pass, the PR can be merged.`, code: `# Step 1: Push your branch to GitHub\ngit push -u origin username/dev\n\n# Step 2: Create PR on GitHub\n# Visit: https://github.com/your-repo\n# Click "Pull Requests" → "New Pull Request"\n# Select:\n#   Base: development  ←  Compare: username/dev\n# Write title & description\n# Click "Create Pull Request"\n\n# === OR create PR via GitHub CLI ===\ngh pr create \\\n  --base development \\\n  --title "feat: add user authentication" \\\n  --body "Implements login/logout with JWT tokens. Closes #42"\n\n# List open PRs\ngh pr list\n\n# View PR details\ngh pr view 15\n\n# Review a PR\ngh pr review 15 --approve\ngh pr review 15 --request-changes --body "Please add error handling"\n\n# Merge a PR\ngh pr merge 15 --squash`, codeLabel: 'Pull Request Workflow', keyPoints: ['Push your branch first, then create PR on GitHub.', 'Select Base (target) and Compare (your branch) branches.', 'Reviewers can Approve, Request Changes, or Comment.', 'All approvals + CI checks must pass before merging.', 'Use GitHub CLI (gh) for command-line PR management.'] },
      { title: 'Merge Pull Request', content: `After a PR is approved by reviewers and all CI checks pass, it can be merged. Merging integrates your branch's changes into the base branch.\n\nMerge Methods:\n- Merge Commit: Creates a merge commit preserving full branch history. Best for feature branches with meaningful commit history.\n- Squash and Merge: Compresses all branch commits into a single commit. Best for keeping a clean main branch history.\n- Rebase and Merge: Replays branch commits on top of the base branch. Creates a linear history without merge commits.\n\nMerging on GitHub:\n1. Visit https://github.com and go to your repository\n2. Click the "Pull Requests" tab\n3. Open the approved Pull Request\n4. Click "Merge Pull Request" (choose merge method)\n5. Click "Confirm Merge"\n6. You'll see "Pull Request successfully merged and closed"\n7. Optionally delete the source branch\n\nAfter merging, all team members should pull the latest changes from the base branch to stay in sync.`, code: `# === Merge on GitHub (Web UI) ===\n# 1. Go to repository → Pull Requests\n# 2. Open the approved PR\n# 3. Click "Merge Pull Request"\n# 4. Select merge method (Squash recommended)\n# 5. Click "Confirm Merge"\n# 6. Delete the source branch (cleanup)\n\n# === Merge via GitHub CLI ===\ngh pr merge 15 --squash --delete-branch\n\n# === After merge: Update your local ===\ngit checkout development\ngit pull origin development\n\n# === Resolve merge conflicts (if any) ===\ngit pull origin development\n# If conflicts appear:\n# 1. Open conflicting files\n# 2. Look for <<<< ==== >>>> markers\n# 3. Choose which changes to keep\n# 4. Remove conflict markers\n# 5. Stage and commit\ngit add .\ngit commit -m "fix: resolve merge conflicts"\ngit push`, codeLabel: 'Merge & Conflict Resolution', keyPoints: ['Squash and Merge creates clean single commits.', 'Delete the source branch after merging.', 'Always pull latest changes after a merge.', 'Resolve conflicts by editing the <<<< ==== >>>> markers.', 'git pull before starting new work prevents conflicts.'] },
      { title: 'Repository Visibility & Branch Rules', content: `Repository Visibility:\n- Public: Anyone on the internet can see this repository. You choose who can commit.\n- Private: Only you and explicitly invited collaborators can see and access this repository.\n- Internal (GitHub Enterprise): Visible to all org members but not the public.\n\nYou can change visibility anytime in Settings → General → Danger Zone.\n\nBranch Protection Rules protect critical branches (main, development) from direct pushes and force pushes. To set up:\n1. Go to repository Settings → Branches\n2. Click "Add branch protection rule"\n3. Enter branch name pattern (e.g., "main")\n4. Enable recommended rules:\n   - Require pull request reviews before merging\n   - Require status checks to pass (CI/CD)\n   - Require conversation resolution before merging\n   - Do not allow force pushes\n   - Do not allow deletions\n   - Require signed commits (optional, for high security)\n\nBranch rules ensure code quality by preventing unreviewed code from entering production.`, keyPoints: ['Public repos are visible to everyone; Private repos are restricted.', 'Branch Protection prevents direct pushes to main/development.', 'Require PR reviews before merging to protected branches.', 'Require CI status checks to pass before allowing merge.', 'Never allow force pushes or deletions on protected branches.'] },
      { title: 'Releases & Tags', content: `Releases are packaged versions of your software with release notes, changelogs, and downloadable assets. They are tied to Git tags, which mark specific points in your repository's history.\n\nTags are like bookmarks pointing to a specific commit. Semantic Versioning (SemVer) is the standard: v1.2.3 where 1 = major (breaking changes), 2 = minor (new features), 3 = patch (bug fixes).\n\nCreating a Release on GitHub:\n1. Go to your repository → "Releases" (right sidebar)\n2. Click "Draft a new release"\n3. Choose a tag (create new, e.g., v1.0.0)\n4. Set the target branch (usually main)\n5. Write a release title and description (changelog)\n6. Optionally upload binary assets (installers, packages)\n7. Click "Publish release"`, code: `# Create a tag locally\ngit tag v1.0.0\ngit tag -a v1.0.0 -m "Release version 1.0.0"\n\n# Push tag to GitHub\ngit push origin v1.0.0\n\n# Push all tags\ngit push origin --tags\n\n# List all tags\ngit tag -l\n\n# Delete a local tag\ngit tag -d v1.0.0\n\n# Delete a remote tag\ngit push origin --delete v1.0.0\n\n# Create release via GitHub CLI\ngh release create v1.0.0 \\\n  --title "Version 1.0.0" \\\n  --notes "Initial stable release with user auth and dashboard"`, codeLabel: 'Tags & Releases', keyPoints: ['Tags mark specific commits (versions) in history.', 'Use Semantic Versioning: vMAJOR.MINOR.PATCH.', 'Releases package your code with notes and downloads.', 'git push origin --tags pushes all tags to GitHub.'] },
      { title: 'Issues & Project Tracking', content: `Issues are GitHub's built-in bug/feature tracker. Every repository has an Issues tab where you can report bugs, request features, ask questions, and track tasks.\n\nCreating an Issue:\n1. Go to repository → Issues tab\n2. Click "New Issue"\n3. Write a clear title and detailed description\n4. Assign to a team member\n5. Add labels (bug, enhancement, documentation, etc.)\n6. Add to a Project board (optional)\n7. Set a milestone (e.g., "v1.0 Release")\n\nGitHub Projects provide Kanban-style boards for task management:\n1. Go to Projects tab → "New Project"\n2. Choose Board, Table, or Roadmap view\n3. Add Issues and Pull Requests as cards\n4. Create columns: To Do, In Progress, In Review, Done\n5. Drag cards between columns as work progresses\n6. Use filters and automation to auto-move cards\n\nProjects integrate directly with Issues and PRs — when a PR closes an issue (using "Closes #42" in the PR description), the linked card automatically moves to Done.`, keyPoints: ['Issues track bugs, features, and tasks.', 'Labels categorize issues (bug, enhancement, etc.).', 'Projects provide Kanban boards for visual tracking.', '"Closes #42" in PR descriptions auto-closes issues.', 'Milestones group issues into release targets.', 'Use @mentions to notify specific team members.'] },
      { title: 'Team Collaboration', content: `GitHub enables seamless team collaboration through repository access control, code reviews, and communication tools.\n\nAdding Collaborators:\n1. Repository Settings → Collaborators\n2. Click "Add people"\n3. Search by username or email\n4. Set role: Read (view only), Triage (manage issues), Write (push code), Maintain (manage settings), Admin (full access)\n\nOrganizations group repositories and team members under one account. Create teams (Frontend, Backend, DevOps) with different access levels across repositories.\n\nCollaboration Best Practices:\n- Always create feature branches — never work directly on main.\n- Write clear commit messages with context.\n- Keep Pull Requests small and focused (one feature per PR).\n- Review others' code promptly and constructively.\n- Use Draft PRs for work-in-progress that needs early feedback.\n- Reference Issues in commits and PRs for traceability.\n- Pull the latest changes from the base branch before pushing.\n- Resolve all review comments before requesting re-review.`, code: `# Daily collaboration workflow\n\n# 1. Start your day — pull latest changes\ngit checkout development\ngit pull origin development\n\n# 2. Create your feature branch\ngit checkout -b username/feature-name\n\n# 3. Do your work, commit frequently\ngit add .\ngit commit -m "feat: add search functionality"\n\n# 4. Push to remote\ngit push -u origin username/feature-name\n\n# 5. Create Pull Request on GitHub\n# Title: "feat: add search functionality"\n# Description: "Implements course search with filtering. Closes #15"\n# Assign reviewers\n# Link to Issue\n\n# 6. Address review feedback\ngit add .\ngit commit -m "fix: address review comments"\ngit push\n\n# 7. After approval and merge — cleanup\ngit checkout development\ngit pull origin development\ngit branch -d username/feature-name`, codeLabel: 'Daily Collaboration Workflow', keyPoints: ['Add collaborators with appropriate access roles.', 'Use Organizations to group repos and team members.', 'Create feature branches for every change.', 'Keep PRs small, focused, and well-described.', 'Review code promptly and constructively.', 'Pull latest changes before starting new work.'] }
    ]
  },
  { id: 'github-actions', title: 'GitHub Actions', description: 'Automate CI/CD workflows with YAML directly in GitHub.',
    officialDocs: 'https://docs.github.com/en/actions', tutorialLink: 'https://docs.github.com/en/actions/quickstart', exerciseLink: null,
    sections: [
      { title: 'What are GitHub Actions', content: `GitHub Actions automates software workflows directly within your GitHub repository. Write YAML files in .github/workflows/ to define CI/CD pipelines triggered by events (push, PR, schedule, manual).\n\nWorkflows contain Jobs (groups of steps running on a virtual machine). Jobs run in parallel by default. Steps execute commands or reuse community-built Actions from the marketplace.`, keyPoints: ['YAML-defined workflows in .github/workflows/.', 'Triggered by events: push, PR, schedule, manual.', 'Jobs run in parallel, steps run sequentially.', 'Actions marketplace: 15,000+ reusable actions.'] },
      { title: 'Workflow Syntax', content: `A workflow file defines: name, trigger events (on), and jobs. Each job specifies a runner (ubuntu-latest, windows-latest), then a series of steps. Steps can run shell commands (run:) or use marketplace actions (uses:).\n\nSecrets store sensitive data (API keys, tokens) securely. Access them via \$\{\{ secrets.SECRET_NAME \}\}. Environment variables can be set at workflow, job, or step level.`, code: `# .github/workflows/ci.yml\nname: CI/CD Pipeline\n\non:\n  push:\n    branches: [main]\n  pull_request:\n    branches: [main]\n\njobs:\n  test:\n    runs-on: ubuntu-latest\n    steps:\n    - uses: actions/checkout@v4\n    - uses: actions/setup-node@v4\n      with:\n        node-version: 20\n        cache: 'npm'\n    - run: npm ci\n    - run: npm test\n    - run: npm run build\n\n  deploy:\n    needs: test        # Runs after test passes\n    if: github.ref == 'refs/heads/main'\n    runs-on: ubuntu-latest\n    steps:\n    - uses: actions/checkout@v4\n    - run: npm ci && npm run build\n    - uses: peaceiris/actions-gh-pages@v3\n      with:\n        github_token: SECRETS.GITHUB_TOKEN\n        publish_dir: ./dist`, codeLabel: 'CI/CD Workflow', keyPoints: ['needs: creates job dependencies (sequential order).', 'if: adds conditional execution.', 'Cache npm/pip for faster builds.', 'Use secrets for API keys and tokens.'] },
      { title: 'Advanced Patterns', content: `Matrix builds test across multiple configurations (OS, language versions) simultaneously. Caching speeds up builds by preserving dependencies between runs. Reusable workflows (workflow_call) share common pipelines across repositories.\n\nScheduled workflows run on cron schedules for tasks like nightly builds, dependency updates, or security scans.`, code: `# Matrix build — test on multiple Node versions\njobs:\n  test:\n    strategy:\n      matrix:\n        node-version: [18, 20, 22]\n        os: [ubuntu-latest, windows-latest]\n    runs-on: MATRIX_OS\n    steps:\n    - uses: actions/checkout@v4\n    - uses: actions/setup-node@v4\n      with:\n        node-version: MATRIX_NODE_VERSION\n    - run: npm ci\n    - run: npm test\n\n# Scheduled workflow (nightly)\non:\n  schedule:\n    - cron: '0 2 * * *'  # Every day at 2 AM UTC\n\n# Docker build and push\n- uses: docker/build-push-action@v5\n  with:\n    push: true\n    tags: user/app:latest`, codeLabel: 'Advanced Workflows', keyPoints: ['Matrix builds test multiple configurations simultaneously.', 'Caching dependencies speeds up builds 50-80%.', 'Scheduled workflows for nightly builds and scans.', 'Reusable workflows share pipelines across repos.'] }
    ]
  }
];
